{
  "executive_summary": "Event sourcing is a strong architectural fit for this loan application audit trail. The compliance requirements — immutable history, full field-change tracking, and point-in-time reconstruction — are natively satisfied by event sourcing's append-only event log. However, event sourcing introduces significant operational complexity (CQRS read models, event schema evolution, eventual consistency) that must be weighed against simpler alternatives like temporal tables with an append-only audit log. For a regulated financial services platform where audit integrity is non-negotiable, the complexity trade-off is justified — event sourcing makes compliance a structural guarantee rather than an application-level concern.",

  "architecture": {
    "components": [
      {
        "name": "Loan Command Service",
        "responsibility": "Accepts loan application commands (submit, update, approve, deny, etc.), validates business rules, and emits domain events. Enforces aggregate invariants before persisting events.",
        "boundaries": "Owns all write operations on loan applications. No direct database reads for query purposes — only loads event stream to hydrate aggregate for command validation."
      },
      {
        "name": "Event Store",
        "responsibility": "Append-only, immutable persistence layer for domain events. Each event is timestamped, sequenced, and tagged with actor identity. Supports stream-per-aggregate reads and global ordered reads.",
        "boundaries": "Write-once, read-many. No updates or deletes permitted. Physical storage must support tamper-evidence (e.g., cryptographic chaining or write-once media for regulatory hardening)."
      },
      {
        "name": "Loan Read Model (Query Service)",
        "responsibility": "Maintains denormalized projections of current loan state and historical views optimized for UI queries, reporting, and search. Rebuilt from event stream.",
        "boundaries": "Eventually consistent with the event store. Can be rebuilt from scratch by replaying events. Owns no business logic — pure data transformation."
      },
      {
        "name": "Audit Projection",
        "responsibility": "Specialized read model that materializes the full audit trail per loan application: who changed what field, when, from what value to what value. Serves compliance queries and regulatory reports.",
        "boundaries": "Read-only projection. Optimized for compliance queries (e.g., 'show all changes to this loan between dates X and Y'). Can reconstruct application state at any point in time by replaying events up to that timestamp."
      },
      {
        "name": "Snapshot Store",
        "responsibility": "Periodically stores aggregate snapshots to avoid replaying long event streams from the beginning. Snapshots are an optimization, not a source of truth.",
        "boundaries": "Optional performance optimization. Snapshots can always be deleted and rebuilt. The event store remains the authoritative source."
      }
    ],
    "interfaces": [
      {
        "from": "API Gateway / UI",
        "to": "Loan Command Service",
        "contract": "Command DTOs (SubmitApplication, UpdateField, ApproveLoan, DenyLoan, etc.) with actor identity, timestamp, and correlation ID",
        "coupling_type": "loose — commands are intent-based, not state-based"
      },
      {
        "from": "Loan Command Service",
        "to": "Event Store",
        "contract": "Append(streamId, expectedVersion, events[]) — optimistic concurrency via expected version",
        "coupling_type": "tight — command service depends on event store for persistence"
      },
      {
        "from": "Event Store",
        "to": "Loan Read Model (Query Service)",
        "contract": "Event subscription (push or poll) — ordered event stream with sequence numbers",
        "coupling_type": "loose — async, eventually consistent"
      },
      {
        "from": "Event Store",
        "to": "Audit Projection",
        "contract": "Event subscription — same mechanism as read model, but projects into audit-specific schema",
        "coupling_type": "loose — async, eventually consistent"
      },
      {
        "from": "API Gateway / UI",
        "to": "Loan Read Model (Query Service)",
        "contract": "Query DTOs — GetLoanById, SearchLoans, GetLoanHistory, GetLoanStateAtTime(timestamp)",
        "coupling_type": "loose — read model is independently queryable"
      },
      {
        "from": "API Gateway / Compliance Tools",
        "to": "Audit Projection",
        "contract": "GetAuditTrail(loanId, dateRange?), ReconstructState(loanId, timestamp)",
        "coupling_type": "loose — dedicated compliance query interface"
      }
    ],
    "data_flow": "1) User submits a command (e.g., UpdateLoanField) with their identity. 2) Command Service loads the aggregate by replaying its event stream (or from snapshot + subsequent events). 3) Aggregate validates the command against business rules. 4) If valid, new domain events are appended to the Event Store with optimistic concurrency. 5) Event subscribers (Read Model, Audit Projection) consume events asynchronously and update their materialized views. 6) Queries hit the read models directly. 7) For point-in-time reconstruction, the Audit Projection replays events up to the requested timestamp.",
    "patterns_used": [
      {
        "pattern": "Event Sourcing",
        "rationale": "The compliance requirements (immutable history, full change tracking, point-in-time reconstruction) are natively satisfied by event sourcing. Rather than bolting audit logging onto a mutable data model, event sourcing makes the audit trail the primary data model — compliance is structural, not behavioral."
      },
      {
        "pattern": "CQRS (Command Query Responsibility Segregation)",
        "rationale": "Event sourcing stores data as events, which is not query-friendly. CQRS separates the write model (event stream) from read models (denormalized projections), allowing each to be optimized independently. The audit projection is a specialized read model."
      },
      {
        "pattern": "Aggregate (DDD)",
        "rationale": "Each loan application is an aggregate with a well-defined consistency boundary. The aggregate protects invariants (e.g., cannot approve an already-denied application) before emitting events."
      },
      {
        "pattern": "Optimistic Concurrency",
        "rationale": "Concurrent modifications to the same loan application are detected via expected version numbers on the event stream, preventing lost updates without pessimistic locking."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Loan Origination",
        "classification": "core",
        "aggregates": [
          "LoanApplication — root aggregate; lifecycle: Draft → Submitted → UnderReview → Approved/Denied/Withdrawn; emits events for every state transition and field change"
        ]
      },
      {
        "name": "Compliance & Audit",
        "classification": "supporting",
        "aggregates": [
          "AuditTrail — projection/read model, not a command-side aggregate; materialized from LoanApplication events"
        ]
      },
      {
        "name": "Identity & Access",
        "classification": "generic",
        "aggregates": [
          "User/Actor — provides the 'who' for audit trail entries; likely an existing IAM system"
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Loan Origination",
        "downstream": "Compliance & Audit",
        "relationship": "Published Language — Loan Origination publishes domain events in a well-defined schema; Compliance subscribes and projects into audit views. No back-pressure or influence from Compliance on the Loan model."
