    {
      "area": "Event schema evolution",
      "evolution_path": "New event types can be added freely. Existing event schemas can be evolved using upcasting (transforming old events to new schema at read time) without modifying stored events. Supports regulatory requirement changes over time."
    },
    {
      "area": "Integration with external systems",
      "evolution_path": "Domain events can be published to external consumers (regulatory reporting systems, analytics, notification services) without modifying core loan logic. New integrations are new subscribers."
    }
  ],

