    "files_to_create_or_modify": [
      "domain/loan/events/ — event definitions (LoanApplicationSubmitted, LoanFieldUpdated, LoanStatusChanged, etc.)",
      "domain/loan/LoanApplicationAggregate — aggregate root with command handlers and invariant enforcement",
      "domain/loan/commands/ — command definitions (SubmitApplication, UpdateField, ApproveLoan, etc.)",
      "infrastructure/eventstore/ — event store adapter (append, load stream, subscribe)",
      "infrastructure/projections/LoanReadModelProjection — builds current-state query model from events",
      "infrastructure/projections/AuditTrailProjection — builds compliance audit view from events",
      "api/commands/LoanCommandController — command API endpoints",
      "api/queries/LoanQueryController — query API endpoints (current state + audit trail)",
      "migration/ — data migration script to convert existing loan_applications rows into import events"
    ],
    "patterns_to_follow": "Each domain event must include: eventId (UUID), aggregateId (loanId), version (sequence number), timestamp, actorId (who), eventType, and payload. Commands must carry actorId from the authenticated session. The aggregate's apply() method must be pure — no side effects, only state transitions. Event handlers in projections must be idempotent (safe to replay). Use optimistic concurrency on every append (expectedVersion). Never put business logic in projections — they are pure data transformations.",
    "pitfalls_to_avoid": [
      "Do NOT store derived/computed data in events — events should capture facts, not calculations. Projections compute derived state.",
      "Do NOT use a single generic 'LoanUpdated' event with a diff payload — define specific, semantically meaningful event types (IncomeVerified, AppraisalReceived, etc.) that capture business intent.",
      "Do NOT skip the crypto-shredding design for PII — retrofitting this is extremely expensive and you will have regulatory exposure in the interim.",
      "Do NOT treat the read model as the source of truth — if the projection is wrong, fix the projection logic and rebuild from events, never patch the read model directly.",
      "Do NOT use the event store as a message bus for cross-service communication — use a separate message broker for integration events to avoid coupling external consumers to your internal event schema.",
      "Do NOT start with a custom event store implementation — use a proven solution (EventStoreDB, or a well-tested library for your stack) to avoid subtle ordering, concurrency, and durability bugs."
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 88,
    "high_confidence_areas": [
      "Event sourcing is a strong fit for the stated compliance requirements — immutability, full history, and point-in-time reconstruction are native capabilities",
      "CQRS is necessary to make event-sourced data queryable for both operational and compliance use cases",
      "Crypto-shredding is the correct approach for GDPR compliance with an immutable event store",
      "The LoanApplication is the natural aggregate boundary"
    ],
    "low_confidence_areas": [
      "Technology stack is unknown — specific tooling recommendations (EventStoreDB vs Marten vs Axon vs custom) depend on the team's language/platform",
      "Team's experience level with event sourcing is unknown — this significantly affects implementation timeline and risk",
      "Scale requirements are unspecified — event store partitioning and snapshot strategies depend on volume (hundreds vs millions of active loans)",
      "Retention policy requirements are unspecified — how long must events be kept, and what archival strategy is needed"
    ],
    "assumptions": [
      "The loan application lifecycle has a bounded number of events (typically tens to low hundreds per application), making event replay feasible",
      "The team is willing to invest in the learning curve for event sourcing and CQRS",
      "The existing system can tolerate a migration period where both old and new persistence models coexist",
      "Regulatory requirements are the primary driver and justify the added architectural complexity over simpler alternatives like temporal tables"
    ]
  }
}

